public int minSwaps(int[] data) {
    int ones = 0;
    for (int d : data) {
        ones += d;
    }
    int cur_ones = 0, max_ones = 0;
    for (int i = 0; i < data.length; i++) {
        cur_ones += data[i];
        if (i >= ones) {
            cur_ones -= data[i - ones];
        }
        max_ones = Math.max(max_ones, cur_ones);
    }
    return ones - max_ones;
}
```


